export const ALL_QUESTIONS = [
  // ─── DSA (20) ───────────────────────────────────────────────────────────────
  { id:1,  category:"DSA", question:"What is the time complexity of finding an element in a balanced BST?", options:["O(1)","O(log n)","O(n)","O(n log n)"], answer:1, explanation:"Each comparison halves the search space in a balanced BST, giving O(log n)." },
  { id:2,  category:"DSA", question:"Which data structure is best for implementing a priority queue?", options:["Stack","Linked List","Heap","Array"], answer:2, explanation:"A heap gives O(log n) insert and O(1) peek for min/max." },
  { id:3,  category:"DSA", question:"What does BFS use internally to traverse a graph?", options:["Stack","Queue","Heap","Hash Map"], answer:1, explanation:"BFS uses a FIFO queue to explore nodes level by level." },
  { id:4,  category:"DSA", question:"What is the worst-case time complexity of QuickSort?", options:["O(n log n)","O(n)","O(n²)","O(log n)"], answer:2, explanation:"QuickSort degrades to O(n²) when the pivot is always the smallest or largest element." },
  { id:5,  category:"DSA", question:"Which algorithm finds shortest paths from a single source in a weighted graph?", options:["BFS","DFS","Dijkstra's","Prim's"], answer:2, explanation:"Dijkstra's uses a min-heap to greedily find the shortest path to each node." },
  { id:6,  category:"DSA", question:"What is the space complexity of merge sort?", options:["O(1)","O(log n)","O(n)","O(n²)"], answer:2, explanation:"Merge sort requires O(n) auxiliary space for temporary arrays during merging." },
  { id:7,  category:"DSA", question:"A hash map has O(1) average lookup. What causes worst-case O(n)?", options:["Too many buckets","Hash collisions filling one bucket","Sorted keys","Large values"], answer:1, explanation:"If all keys hash to the same bucket, lookups degrade to O(n) linear search." },
  { id:8,  category:"DSA", question:"Which traversal of a BST produces elements in sorted order?", options:["Pre-order","Post-order","In-order","Level-order"], answer:2, explanation:"In-order traversal (left → root → right) visits nodes in ascending sorted order." },
  { id:9,  category:"DSA", question:"What is a stack's primary property?", options:["FIFO","LIFO","Random access","Sorted order"], answer:1, explanation:"A stack is Last In First Out — the last element pushed is the first popped." },
  { id:10, category:"DSA", question:"Which data structure is used in DFS?", options:["Queue","Stack","Heap","Linked List"], answer:1, explanation:"DFS uses a stack (or recursion which uses the call stack) to explore paths deeply before backtracking." },
  { id:11, category:"DSA", question:"What is the time complexity of inserting into a sorted array?", options:["O(1)","O(log n)","O(n)","O(n log n)"], answer:2, explanation:"You need to shift elements to maintain order, which takes O(n) in the worst case." },
  { id:12, category:"DSA", question:"What does dynamic programming optimize?", options:["Memory usage","Repeated subproblem computations","Network calls","Sorting speed"], answer:1, explanation:"DP stores results of subproblems to avoid recomputing them, trading memory for speed." },
  { id:13, category:"DSA", question:"What is the time complexity of binary search?", options:["O(1)","O(log n)","O(n)","O(n log n)"], answer:1, explanation:"Binary search halves the search space each step, giving O(log n)." },
  { id:14, category:"DSA", question:"Which sorting algorithm is stable and has O(n log n) worst case?", options:["QuickSort","HeapSort","MergeSort","BubbleSort"], answer:2, explanation:"MergeSort is stable and guarantees O(n log n) in all cases." },
  { id:15, category:"DSA", question:"What is a trie used for?", options:["Graph traversal","Prefix-based string search","Sorting numbers","Hashing"], answer:1, explanation:"A trie stores strings character by character, enabling fast prefix lookups and autocomplete." },
  { id:16, category:"DSA", question:"What is the time complexity of accessing an element in an array by index?", options:["O(log n)","O(n)","O(1)","O(n²)"], answer:2, explanation:"Arrays store elements contiguously in memory so index access is O(1) constant time." },
  { id:17, category:"DSA", question:"What problem does a Union-Find (Disjoint Set) data structure solve?", options:["Shortest path","Detecting cycles / finding connected components","Sorting","String matching"], answer:1, explanation:"Union-Find efficiently tracks which elements are in the same connected component." },
  { id:18, category:"DSA", question:"What is a min-heap property?", options:["Parent is always greater than children","Parent is always less than or equal to children","All leaves are at the same level","Left child is always smaller"], answer:1, explanation:"In a min-heap, every parent node is smaller than or equal to its children, so the minimum is at the root." },
  { id:19, category:"DSA", question:"What is the average time complexity of inserting into a hash table?", options:["O(n)","O(log n)","O(1)","O(n log n)"], answer:2, explanation:"With a good hash function and low load factor, hash table insertions are O(1) on average." },
  { id:20, category:"DSA", question:"Which algorithm finds the minimum spanning tree of a graph?", options:["Dijkstra's","BFS","Kruskal's","Topological Sort"], answer:2, explanation:"Kruskal's algorithm sorts edges by weight and adds them greedily without creating cycles." },

  // ─── SYSTEM DESIGN (20) ──────────────────────────────────────────────────────
  { id:21, category:"System Design", question:"Which consistency model does DNS use?", options:["Strong","Linearizability","Eventual","Sequential"], answer:2, explanation:"DNS propagates changes gradually with TTL-based caching — classic eventual consistency." },
  { id:22, category:"System Design", question:"What is the primary purpose of a CDN?", options:["DB replication","App load balancing","Serving content from geo-close nodes","Encrypting traffic"], answer:2, explanation:"CDNs cache static assets at edge nodes near users to reduce latency and origin load." },
  { id:23, category:"System Design", question:"In CAP theorem, during a network partition a system must choose between:", options:["Consistency & Latency","Availability & Latency","Consistency & Availability","Durability & Throughput"], answer:2, explanation:"CAP: during a partition, sacrifice Consistency or Availability — you can't have both." },
  { id:24, category:"System Design", question:"What does horizontal scaling mean?", options:["Adding more CPU/RAM to one machine","Adding more machines to a pool","Optimizing database queries","Caching at the app layer"], answer:1, explanation:"Horizontal scaling (scale out) adds more machines. Vertical scaling (scale up) upgrades one machine." },
  { id:25, category:"System Design", question:"Which database type is best for storing a social graph?", options:["Relational (SQL)","Key-Value Store","Graph Database","Column Store"], answer:2, explanation:"Graph databases store nodes and edges natively, making relationship traversals highly efficient." },
  { id:26, category:"System Design", question:"What is the role of a message queue in a distributed system?", options:["Storing user sessions","Decoupling producers and consumers for async processing","Serving static files","Load balancing HTTP requests"], answer:1, explanation:"Message queues decouple services so producers don't wait for consumers, improving resilience." },
  { id:27, category:"System Design", question:"What is database sharding?", options:["Backing up a database","Splitting data across multiple databases by a shard key","Replicating data to read replicas","Encrypting database columns"], answer:1, explanation:"Sharding splits a large dataset across multiple DB instances to distribute load and scale horizontally." },
  { id:28, category:"System Design", question:"What is the purpose of a reverse proxy?", options:["To encrypt client traffic","To sit in front of servers and forward client requests to them","To cache DNS records","To monitor database queries"], answer:1, explanation:"A reverse proxy (like Nginx) receives requests and forwards them to backend servers, hiding server details." },
  { id:29, category:"System Design", question:"What is the difference between SQL and NoSQL databases?", options:["SQL is faster","NoSQL always uses more storage","SQL uses structured schemas and tables; NoSQL is flexible and schema-less","There is no difference"], answer:2, explanation:"SQL enforces a rigid schema with tables/relations. NoSQL (documents, key-value, graphs) is flexible and scales horizontally." },
  { id:30, category:"System Design", question:"What is rate limiting used for?", options:["Speeding up API responses","Preventing abuse by limiting how many requests a client can make in a time window","Encrypting API keys","Compressing HTTP responses"], answer:1, explanation:"Rate limiting protects services from abuse, DDoS attacks, and overload by capping request frequency." },
  { id:31, category:"System Design", question:"What is a write-through cache?", options:["Cache is written after the DB","Data is written to cache and DB simultaneously","Cache is never written","Only reads go through cache"], answer:1, explanation:"Write-through writes to both cache and database at the same time, keeping them consistent." },
  { id:32, category:"System Design", question:"What does PACELC stand for in distributed systems?", options:["A type of database","An extension to CAP that also considers latency tradeoffs","A caching strategy","A load balancing algorithm"], answer:1, explanation:"PACELC extends CAP: even without a Partition, systems must choose between Latency and Consistency." },
  { id:33, category:"System Design", question:"What is consistent hashing used for?", options:["Sorting data","Distributing data across nodes so that adding/removing nodes minimizes remapping","Encrypting cache keys","Balancing CPU load"], answer:1, explanation:"Consistent hashing minimizes key remapping when nodes are added or removed in a distributed cache." },
  { id:34, category:"System Design", question:"What is a circuit breaker pattern?", options:["A way to encrypt API calls","Stops calls to a failing service to prevent cascading failures","A database backup strategy","A load balancing technique"], answer:1, explanation:"Circuit breakers detect repeated failures and short-circuit calls to give a failing service time to recover." },
  { id:35, category:"System Design", question:"What is the difference between latency and throughput?", options:["They are the same thing","Latency is time for one request; throughput is requests per second","Latency measures CPU usage; throughput measures memory","Throughput is always higher than latency"], answer:1, explanation:"Latency = how long one request takes. Throughput = how many requests the system handles per unit time." },
  { id:36, category:"System Design", question:"What is an API gateway?", options:["A physical network device","A single entry point that routes requests, handles auth, and aggregates services","A type of database","A CDN node"], answer:1, explanation:"An API gateway sits in front of microservices handling routing, auth, rate limiting, and request aggregation." },
  { id:37, category:"System Design", question:"What is eventual consistency?", options:["All nodes always have the same data","Given enough time without updates, all nodes will converge to the same value","Data is never consistent","Only the primary node is consistent"], answer:1, explanation:"Eventual consistency guarantees convergence over time but allows temporary inconsistency between nodes." },
  { id:38, category:"System Design", question:"What is the purpose of a read replica in a database setup?", options:["To replace the primary database","To handle write operations","To offload read traffic from the primary database","To encrypt data"], answer:2, explanation:"Read replicas serve read queries so the primary database can focus on writes, improving performance." },
  { id:39, category:"System Design", question:"What does idempotency mean in APIs?", options:["The API is very fast","Making the same request multiple times has the same effect as making it once","The API never fails","The API returns the same response format always"], answer:1, explanation:"Idempotent operations can be safely retried. GET, PUT, DELETE are idempotent; POST typically is not." },
  { id:40, category:"System Design", question:"What is a service mesh?", options:["A type of database cluster","Infrastructure layer handling service-to-service communication (retries, auth, observability)","A caching layer","A UI component library"], answer:1, explanation:"A service mesh (like Istio) manages internal microservice communication with features like retries, tracing, and mTLS." },

  // ─── OOP (20) ────────────────────────────────────────────────────────────────
  { id:41, category:"OOP", question:"Which SOLID principle says a class should have only one reason to change?", options:["Open/Closed","Single Responsibility","Liskov Substitution","Interface Segregation"], answer:1, explanation:"SRP: each class encapsulates exactly one concern or responsibility." },
  { id:42, category:"OOP", question:"What is the difference between composition and inheritance?", options:["Same thing","Inheritance is 'is-a', composition is 'has-a'","Composition is only for interfaces","Inheritance is always preferred"], answer:1, explanation:"Composition models 'has-a' (Car has Engine). Inheritance models 'is-a' (Dog is Animal). Prefer composition for flexibility." },
  { id:43, category:"OOP", question:"What design pattern provides a simplified interface to a complex subsystem?", options:["Observer","Strategy","Facade","Decorator"], answer:2, explanation:"The Facade pattern hides complexity behind a unified interface." },
  { id:44, category:"OOP", question:"Which pattern lets you define a family of algorithms and make them interchangeable?", options:["Singleton","Observer","Command","Strategy"], answer:3, explanation:"Strategy encapsulates algorithms so they can be swapped at runtime without changing client code." },
  { id:45, category:"OOP", question:"What does the Open/Closed principle state?", options:["Classes should be open for modification","Classes should be open for extension but closed for modification","All classes must be abstract","Methods should always be public"], answer:1, explanation:"OCP: you should be able to add new behavior by extending, not by modifying existing code." },
  { id:46, category:"OOP", question:"What is polymorphism in OOP?", options:["A class having multiple constructors","The ability of different objects to respond to the same interface in different ways","Hiding internal state","Inheriting from multiple classes"], answer:1, explanation:"Polymorphism lets you call the same method on different objects and get different behavior (e.g. via method overriding)." },
  { id:47, category:"OOP", question:"What is encapsulation?", options:["Inheriting from a parent class","Hiding internal state and exposing only a public interface","Creating multiple instances","Overriding methods"], answer:1, explanation:"Encapsulation bundles data and methods together and restricts direct access to internal state." },
  { id:48, category:"OOP", question:"What is the Singleton pattern?", options:["A class with no methods","Ensures a class has only one instance and provides a global access point","A class that can't be inherited","A pattern for creating families of objects"], answer:1, explanation:"Singleton restricts instantiation to one object — useful for shared resources like config or a DB connection." },
  { id:49, category:"OOP", question:"What is the Observer pattern?", options:["One object controls all others","Objects subscribe to another object and are notified when it changes","A class observes its own state","Logging user actions"], answer:1, explanation:"Observer defines a one-to-many dependency so when one object changes state, all dependents are notified automatically." },
  { id:50, category:"OOP", question:"What is the Liskov Substitution Principle?", options:["Subclasses should be replaceable for their parent class without breaking the program","All classes must have a superclass","Interfaces must match their implementations","Methods must return the same type"], answer:0, explanation:"LSP: if S is a subtype of T, you should be able to use S wherever T is expected without issues." },
  { id:51, category:"OOP", question:"What is the Factory pattern?", options:["A pattern for destroying objects","Creates objects without specifying the exact class to create","Forces all objects to be the same type","A singleton variant"], answer:1, explanation:"Factory pattern delegates object creation to a method or class, decoupling creation from usage." },
  { id:52, category:"OOP", question:"What is the Decorator pattern?", options:["Adds behavior to objects dynamically without modifying their class","Removes behavior from objects","A type of inheritance","Converts one interface to another"], answer:0, explanation:"Decorator wraps objects to add new functionality at runtime — like adding toppings to a pizza." },
  { id:53, category:"OOP", question:"What is abstraction in OOP?", options:["Hiding implementation details and showing only essential features","Making all methods public","Copying an object","Preventing inheritance"], answer:0, explanation:"Abstraction exposes what an object does without revealing how it does it — e.g. a car's steering wheel hides the engine." },
  { id:54, category:"OOP", question:"What is method overloading?", options:["Overriding a parent method","Multiple methods with the same name but different parameters","Calling a method multiple times","A method that returns void"], answer:1, explanation:"Overloading lets you define multiple methods with the same name but different signatures in the same class." },
  { id:55, category:"OOP", question:"What is the Command pattern used for?", options:["Routing HTTP requests","Encapsulating a request as an object, enabling undo/redo and queuing","Sorting data","Observing state changes"], answer:1, explanation:"Command encapsulates operations as objects, allowing deferred execution, undo, and logging." },
  { id:56, category:"OOP", question:"What does the Interface Segregation Principle state?", options:["All methods should be in one interface","Clients should not be forced to depend on interfaces they don't use","Interfaces must be abstract","Only one interface per class"], answer:1, explanation:"ISP: split large interfaces into smaller specific ones so classes only implement what they need." },
  { id:57, category:"OOP", question:"What is the Adapter pattern?", options:["Speeds up slow code","Converts one interface into another that a client expects","Creates objects in bulk","Monitors object state"], answer:1, explanation:"Adapter acts as a bridge between incompatible interfaces — like a power adapter for different outlets." },
  { id:58, category:"OOP", question:"What is the difference between an abstract class and an interface?", options:["No difference","Abstract classes can have implementations; interfaces (traditionally) cannot","Interfaces are faster","Abstract classes can't be inherited"], answer:1, explanation:"Abstract classes can have concrete methods and state. Interfaces define a pure contract with no implementation (in most languages)." },
  { id:59, category:"OOP", question:"What is the Builder pattern?", options:["Constructs a complex object step by step","Destroys objects safely","Observes object creation","A variant of Singleton"], answer:0, explanation:"Builder separates the construction of a complex object from its representation, useful when there are many optional parameters." },
  { id:60, category:"OOP", question:"What is the Proxy pattern?", options:["Directly exposes internal state","Provides a surrogate that controls access to another object","A type of inheritance","Speeds up method calls"], answer:1, explanation:"Proxy controls access to an object — useful for lazy loading, access control, or logging." },

  // ─── OS (20) ─────────────────────────────────────────────────────────────────
  { id:61, category:"OS", question:"What four conditions must ALL be present for a deadlock?", options:["Race, starvation, thrashing, preemption","Mutual exclusion, hold & wait, no preemption, circular wait","Context switch, interrupt, semaphore, mutex","Cache miss, page fault, TLB miss, swap"], answer:1, explanation:"These are the Coffman conditions. Breaking any one prevents deadlock." },
  { id:62, category:"OS", question:"What is the difference between a process and a thread?", options:["No difference","Threads are heavier","Processes have separate memory; threads share memory within a process","A process can only have one thread"], answer:2, explanation:"Processes are isolated with own address space. Threads share memory within a process." },
  { id:63, category:"OS", question:"What problem does a semaphore solve?", options:["Memory leaks","Deadlock detection","Synchronizing access to shared resources","CPU scheduling"], answer:2, explanation:"Semaphores use wait/signal operations to control access to shared resources and prevent race conditions." },
  { id:64, category:"OS", question:"What is virtual memory?", options:["Extra physical RAM","An abstraction giving each process its own address space using disk as overflow","A type of CPU cache","A network storage protocol"], answer:1, explanation:"Virtual memory maps virtual addresses to physical RAM and disk, giving processes isolated address spaces." },
  { id:65, category:"OS", question:"What is a context switch?", options:["Changing a file's permissions","The OS saving one process's state and loading another's to switch between them","A memory allocation","A network packet switch"], answer:1, explanation:"A context switch saves the CPU registers of the running process and restores another's, enabling multitasking." },
  { id:66, category:"OS", question:"What is the difference between a mutex and a semaphore?", options:["They are identical","A mutex is a binary lock owned by one thread; a semaphore is a counter allowing N threads","A semaphore is faster","Mutexes can't be used in user space"], answer:1, explanation:"A mutex provides mutual exclusion for one thread at a time. A semaphore can allow multiple (counting semaphore) or one (binary)." },
  { id:67, category:"OS", question:"What is thrashing in an OS?", options:["CPU overheating","Excessive paging where the OS spends more time swapping than executing","A deadlock variant","High network traffic"], answer:1, explanation:"Thrashing occurs when the system constantly swaps pages in and out because working sets don't fit in RAM." },
  { id:68, category:"OS", question:"What is the purpose of a page table?", options:["Storing file metadata","Mapping virtual addresses to physical memory addresses","Managing CPU registers","Scheduling processes"], answer:1, explanation:"The page table is a data structure the OS uses to translate virtual addresses to physical RAM addresses." },
  { id:69, category:"OS", question:"What is a system call?", options:["A function call between two apps","A way for user-space programs to request services from the OS kernel","A network request","A method call in OOP"], answer:1, explanation:"System calls are the interface between user programs and the OS kernel — e.g. open(), read(), fork()." },
  { id:70, category:"OS", question:"What scheduling algorithm gives each process equal time slices in rotation?", options:["FIFO","Shortest Job First","Round Robin","Priority Scheduling"], answer:2, explanation:"Round Robin assigns each process a fixed time quantum in circular order, ensuring fairness." },
  { id:71, category:"OS", question:"What is a race condition?", options:["CPU running too fast","Two threads accessing shared data with at least one write, without synchronization","A scheduling bug","A memory leak"], answer:1, explanation:"A race condition occurs when program outcome depends on unpredictable timing of concurrent operations." },
  { id:72, category:"OS", question:"What is the difference between preemptive and cooperative multitasking?", options:["No difference","Preemptive: OS can interrupt a process; Cooperative: processes voluntarily yield","Cooperative is always faster","Preemptive uses more memory"], answer:1, explanation:"Preemptive multitasking (modern OS) lets the kernel interrupt processes. Cooperative requires processes to yield CPU voluntarily." },
  { id:73, category:"OS", question:"What is a TLB (Translation Lookaside Buffer)?", options:["A type of RAM","A hardware cache for recent virtual-to-physical address translations","A disk cache","A CPU register"], answer:1, explanation:"The TLB caches recent page table lookups so the CPU doesn't have to walk the full page table every memory access." },
  { id:74, category:"OS", question:"What is the kernel?", options:["A user application","The core of the OS that manages hardware, memory, processes, and system calls","A file system","A bootloader"], answer:1, explanation:"The kernel is the privileged core of the OS that directly controls hardware and provides services to user programs." },
  { id:75, category:"OS", question:"What is copy-on-write (COW)?", options:["Copying files on write","An optimization where forked processes share memory until one writes, then a copy is made","A backup strategy","A file compression method"], answer:1, explanation:"COW lets forked processes share the same memory pages until one modifies a page, only then making a copy — saving memory." },
  { id:76, category:"OS", question:"What is starvation in OS scheduling?", options:["A process consuming too much CPU","A low-priority process never getting CPU time because high-priority processes always run","A deadlock variant","Running out of disk space"], answer:1, explanation:"Starvation happens when a process waits indefinitely because higher-priority processes always preempt it." },
  { id:77, category:"OS", question:"What is an interrupt?", options:["A program error","A signal to the CPU to stop current execution and handle an urgent event","A network packet","A memory allocation failure"], answer:1, explanation:"Interrupts signal the CPU (from hardware or software) to pause current work and handle something urgent like I/O completion." },
  { id:78, category:"OS", question:"What is the difference between internal and external fragmentation?", options:["They are the same","Internal: wasted space inside allocated blocks; External: free memory scattered in small chunks","Internal is always larger","External only occurs on disk"], answer:1, explanation:"Internal fragmentation wastes space within allocated memory. External fragmentation wastes space between allocations." },
  { id:79, category:"OS", question:"What does fork() do in Unix?", options:["Deletes a process","Creates a child process that is a copy of the parent","Terminates the calling process","Switches to a new thread"], answer:1, explanation:"fork() creates a new child process as a nearly identical copy of the parent, running the same code from that point." },
  { id:80, category:"OS", question:"What is a zombie process?", options:["A process consuming 100% CPU","A process that has finished but whose exit status hasn't been collected by the parent","A virus","A background daemon"], answer:1, explanation:"A zombie process has exited but remains in the process table until the parent calls wait() to collect its exit code." },

  // ─── NETWORKING (20) ─────────────────────────────────────────────────────────
  { id:81, category:"Networking", question:"What does TCP provide that UDP does not?", options:["Speed","Lower overhead","Reliable ordered delivery with congestion control","Multicast support"], answer:2, explanation:"TCP handshakes, ACKs, and retransmits ensure reliability. UDP is faster but fire-and-forget." },
  { id:82, category:"Networking", question:"What happens during a TCP three-way handshake?", options:["SYN → ACK → FIN","SYN → SYN-ACK → ACK","ACK → SYN → FIN","CONNECT → ACCEPT → SEND"], answer:1, explanation:"Client sends SYN, server replies SYN-ACK, client confirms with ACK. Connection established." },
  { id:83, category:"Networking", question:"What is the purpose of a load balancer?", options:["Encrypting traffic","Distributing requests across multiple servers","Caching static assets","Managing DNS records"], answer:1, explanation:"Load balancers distribute incoming traffic across servers to prevent overload and improve availability." },
  { id:84, category:"Networking", question:"What does HTTP stand for and what layer does it operate on?", options:["Hardware Transfer Protocol, Layer 2","HyperText Transfer Protocol, Application Layer (Layer 7)","Host Transfer Protocol, Layer 4","High Throughput Protocol, Layer 3"], answer:1, explanation:"HTTP is HyperText Transfer Protocol operating at Layer 7 (Application) of the OSI model." },
  { id:85, category:"Networking", question:"What is the difference between HTTP and HTTPS?", options:["No difference","HTTPS encrypts traffic using TLS/SSL","HTTPS is faster","HTTP uses port 443"], answer:1, explanation:"HTTPS wraps HTTP in TLS encryption, ensuring data confidentiality and integrity between client and server." },
  { id:86, category:"Networking", question:"What does DNS do?", options:["Assigns IP addresses","Translates domain names to IP addresses","Routes packets","Encrypts traffic"], answer:1, explanation:"DNS (Domain Name System) resolves human-readable domain names like google.com to IP addresses." },
  { id:87, category:"Networking", question:"What is the difference between TCP and IP?", options:["They are the same","IP handles addressing/routing; TCP handles reliable delivery on top of IP","TCP is faster","IP works at the application layer"], answer:1, explanation:"IP is responsible for addressing and routing packets. TCP provides reliability and ordering on top of IP." },
  { id:88, category:"Networking", question:"What is a subnet mask used for?", options:["Encrypting packets","Determining which part of an IP address is the network vs host portion","Routing between countries","Assigning MAC addresses"], answer:1, explanation:"A subnet mask divides an IP address into network and host portions, defining the size of the local network." },
  { id:89, category:"Networking", question:"What port does HTTPS use by default?", options:["80","21","443","8080"], answer:2, explanation:"HTTPS uses port 443 by default. HTTP uses port 80." },
  { id:90, category:"Networking", question:"What is a WebSocket?", options:["A type of HTTP request","A protocol providing full-duplex persistent communication over a single TCP connection","A firewall rule","A DNS record type"], answer:1, explanation:"WebSockets enable real-time bidirectional communication between client and server — used in chat apps and live feeds." },
  { id:91, category:"Networking", question:"What is the OSI model?", options:["A database architecture","A 7-layer conceptual framework for how network communication works","A type of encryption","A routing protocol"], answer:1, explanation:"OSI (Open Systems Interconnection) has 7 layers: Physical, Data Link, Network, Transport, Session, Presentation, Application." },
  { id:92, category:"Networking", question:"What is NAT (Network Address Translation)?", options:["A routing protocol","Maps private IP addresses to a public IP so multiple devices share one public address","A type of firewall","A DNS technique"], answer:1, explanation:"NAT allows many devices on a private network to share one public IP address, conserving the IPv4 address space." },
  { id:93, category:"Networking", question:"What is the difference between a hub and a switch?", options:["They are identical","A hub broadcasts to all ports; a switch sends to specific destination MAC addresses","A switch is slower","Hubs operate at Layer 3"], answer:1, explanation:"Hubs blindly broadcast packets to all ports. Switches are smarter — they learn MAC addresses and forward only to the right port." },
  { id:94, category:"Networking", question:"What is a CDN edge node?", options:["A database server","A server geographically close to users that caches content","A DNS server","A load balancer"], answer:1, explanation:"CDN edge nodes are distributed servers that cache content close to users to reduce latency." },
  { id:95, category:"Networking", question:"What does ARP do?", options:["Routes packets between networks","Resolves an IP address to a MAC address on a local network","Encrypts packets","Assigns IP addresses"], answer:1, explanation:"ARP (Address Resolution Protocol) maps a known IP address to a MAC address within the same local network." },
  { id:96, category:"Networking", question:"What is a firewall?", options:["A physical server","A system that monitors and controls incoming/outgoing network traffic based on rules","A type of encryption","A DNS server"], answer:1, explanation:"Firewalls filter network traffic based on rules, blocking unauthorized access while allowing legitimate traffic." },
  { id:97, category:"Networking", question:"What is the difference between IPv4 and IPv6?", options:["No difference","IPv4 uses 32-bit addresses (4 billion); IPv6 uses 128-bit addresses (virtually unlimited)","IPv6 is slower","IPv4 is newer"], answer:1, explanation:"IPv4 has ~4 billion addresses which are exhausted. IPv6 has 2^128 addresses to meet modern demand." },
  { id:98, category:"Networking", question:"What is a REST API?", options:["A database query language","An architectural style using HTTP methods (GET, POST, PUT, DELETE) to interact with resources","A type of WebSocket","A binary protocol"], answer:1, explanation:"REST uses standard HTTP verbs and stateless communication to create scalable web APIs." },
  { id:99, category:"Networking", question:"What is TCP slow start?", options:["TCP deliberately slowing down","A congestion control mechanism that gradually increases transmission rate to find available bandwidth","A firewall rule","A DNS technique"], answer:1, explanation:"TCP slow start begins with a small congestion window and doubles it each round trip until packet loss is detected." },
  { id:100, category:"Networking", question:"What is the purpose of the TTL field in a DNS record?", options:["Encrypts the record","Tells resolvers how long to cache the record before requesting a fresh copy","Defines record priority","Sets the record type"], answer:1, explanation:"TTL (Time To Live) controls how long DNS resolvers cache a record — shorter TTL means faster propagation of changes." },

  // ─── CONCURRENCY (20) ────────────────────────────────────────────────────────
  { id:101, category:"Concurrency", question:"What is a race condition?", options:["CPU running too hot","Two threads accessing shared data with at least one write, without synchronization","A network packet arriving out of order","A memory leak in a loop"], answer:1, explanation:"A race condition occurs when outcome depends on unpredictable timing of concurrent operations." },
  { id:102, category:"Concurrency", question:"What does the 'volatile' keyword guarantee in Java?", options:["Thread safety for compound operations","Visibility — changes are immediately visible to other threads","The variable cannot be null","Atomic increment"], answer:1, explanation:"'volatile' ensures visibility but NOT atomicity. For compound ops (i++), use AtomicInteger or synchronization." },
  { id:103, category:"Concurrency", question:"What is a deadlock in concurrent programming?", options:["A process running too long","Two or more threads waiting on each other indefinitely, none able to proceed","A memory overflow","A slow network call"], answer:1, explanation:"Deadlock occurs when threads hold locks and wait for locks held by others, creating a circular dependency." },
  { id:104, category:"Concurrency", question:"What is the purpose of the synchronized keyword in Java?", options:["Makes code run faster","Ensures only one thread can execute a block at a time","Prevents memory leaks","Makes variables immutable"], answer:1, explanation:"synchronized acquires a monitor lock, ensuring mutual exclusion so only one thread executes the block at a time." },
  { id:105, category:"Concurrency", question:"What is the difference between parallelism and concurrency?", options:["They are the same","Concurrency is about dealing with multiple tasks; parallelism is physically running them simultaneously","Parallelism is slower","Concurrency requires multiple CPUs"], answer:1, explanation:"Concurrency = structure (managing multiple tasks). Parallelism = execution (running multiple tasks at the exact same time)." },
  { id:106, category:"Concurrency", question:"What is a thread pool?", options:["A group of threads that are sleeping","A collection of pre-created threads that pick up and execute tasks from a queue","A memory allocation strategy","A deadlock prevention technique"], answer:1, explanation:"Thread pools reuse threads to avoid the overhead of creating/destroying threads for each task." },
  { id:107, category:"Concurrency", question:"What is the actor model of concurrency?", options:["Threads sharing memory directly","Independent actors that communicate only by passing messages, avoiding shared state","A CPU scheduling algorithm","A type of mutex"], answer:1, explanation:"The actor model avoids shared state entirely — actors process one message at a time and communicate via message passing." },
  { id:108, category:"Concurrency", question:"What is a future/promise in async programming?", options:["A guarantee about performance","A placeholder for a value that will be available eventually","A type of thread","A network timeout"], answer:1, explanation:"A Future/Promise represents the eventual result of an async operation — you can attach callbacks or await its value." },
  { id:109, category:"Concurrency", question:"What is optimistic locking?", options:["Always acquiring locks before reading","Proceeding without a lock and checking for conflicts at commit time","A deadlock prevention strategy","Using multiple locks simultaneously"], answer:1, explanation:"Optimistic locking assumes conflicts are rare, so it reads without locking and validates at write time (e.g. using version numbers)." },
  { id:110, category:"Concurrency", question:"What is the happens-before relationship in Java Memory Model?", options:["A scheduling guarantee","A guarantee that one action's effects are visible to another specific action","A lock ordering rule","A garbage collection concept"], answer:1, explanation:"Happens-before ensures that memory writes by one thread are visible to another — established by synchronized, volatile, thread start/join." },
  { id:111, category:"Concurrency", question:"What is a livelock?", options:["A deadlock that resolves itself","Threads are active but constantly reacting to each other without making progress","A type of race condition","Threads running too fast"], answer:1, explanation:"Livelock threads keep responding to each other and changing state, but neither makes actual progress — like two people dodging each other in a hallway." },
  { id:112, category:"Concurrency", question:"What is the CAS (Compare-And-Swap) operation?", options:["A sorting algorithm","An atomic operation that updates a value only if it matches an expected value","A cache invalidation strategy","A deadlock detection method"], answer:1, explanation:"CAS atomically checks if a memory location has an expected value and updates it if so — the basis for lock-free data structures." },
  { id:113, category:"Concurrency", question:"What is starvation in concurrent programming?", options:["Running out of memory","A thread never getting access to a resource because others always get priority","A type of deadlock","CPU throttling"], answer:1, explanation:"Starvation occurs when a thread perpetually waits for a resource that keeps being acquired by higher-priority threads." },
  { id:114, category:"Concurrency", question:"What is event-driven programming?", options:["Code that runs on a schedule","Program flow determined by events like user input, messages, or I/O completion","A type of multithreading","Batch processing"], answer:1, explanation:"Event-driven code registers handlers that fire in response to events, common in UI frameworks and Node.js." },
  { id:115, category:"Concurrency", question:"What is the difference between a process and a thread in terms of memory?", options:["No difference","Threads share the heap of their process; processes have separate memory spaces","Processes are faster","Threads use more memory"], answer:1, explanation:"Threads share heap memory within a process (fast but risky). Processes are isolated (safer but communication is harder)." },
  { id:116, category:"Concurrency", question:"What is async/await?", options:["A thread creation pattern","Syntactic sugar over promises making async code look synchronous","A locking mechanism","A CPU optimization"], answer:1, explanation:"async/await lets you write asynchronous code in a synchronous style, awaiting promises without blocking the thread." },
  { id:117, category:"Concurrency", question:"What is the readers-writers problem?", options:["A file system issue","Multiple readers can access data simultaneously, but writers need exclusive access","A deadlock scenario","A network protocol issue"], answer:1, explanation:"The readers-writers problem balances allowing multiple concurrent readers vs. giving writers exclusive access to shared data." },
  { id:118, category:"Concurrency", question:"What is a spin lock?", options:["A type of semaphore","A lock where a thread continuously checks if the lock is free instead of sleeping","A deadlock prevention technique","A thread pool strategy"], answer:1, explanation:"Spin locks busy-wait in a loop checking the lock — efficient for short waits but wastes CPU on long ones." },
  { id:119, category:"Concurrency", question:"What is the fork-join model?", options:["Creating and deleting files","Splitting a task into parallel subtasks (fork), then combining results (join)","A network protocol","A database transaction model"], answer:1, explanation:"Fork-join splits work across threads then waits for all to complete before combining results — used in parallel stream processing." },
  { id:120, category:"Concurrency", question:"What is green threading?", options:["Environmentally friendly code","User-space threads managed by a runtime rather than the OS kernel","A type of mutex","A scheduling algorithm"], answer:1, explanation:"Green threads are managed by the language runtime (e.g. Go goroutines), not the OS — lighter weight and faster to create than OS threads." },

  // ─── DATABASES (20) ──────────────────────────────────────────────────────────
  { id:121, category:"Databases", question:"What do ACID properties guarantee?", options:["Speed, Indexing, Durability, Caching","Atomicity, Consistency, Isolation, Durability","Availability, Concurrency, Integrity, Distribution","Asynchronous, Concurrent, Independent, Distributed"], answer:1, explanation:"ACID ensures transactions are all-or-nothing, leave DB in valid state, are isolated, and persist after commit." },
  { id:122, category:"Databases", question:"When should you use an index on a database column?", options:["Always, on every column","When frequently used in WHERE, JOIN, or ORDER BY clauses","Only on primary keys","Never — they slow down reads"], answer:1, explanation:"Indexes speed up reads on frequently queried columns at the cost of slower writes and extra storage." },
  { id:123, category:"Databases", question:"What is the N+1 query problem?", options:["Having more than N tables","Executing 1 query to get N records then N queries to get related data","Using N indexes on one table","Joining more than N tables"], answer:1, explanation:"N+1 means 1 query fetches a list, then N queries fetch details for each item — fixed with eager loading or JOINs." },
  { id:124, category:"Databases", question:"What is database normalization?", options:["Speeding up queries","Organizing data to reduce redundancy and improve integrity by applying normal forms","Encrypting data","Backing up data"], answer:1, explanation:"Normalization reduces data duplication by splitting data into related tables following normal forms (1NF, 2NF, 3NF)." },
  { id:125, category:"Databases", question:"What is the difference between INNER JOIN and LEFT JOIN?", options:["No difference","INNER JOIN returns matching rows only; LEFT JOIN returns all left rows plus matches","LEFT JOIN is faster","INNER JOIN works on more tables"], answer:1, explanation:"INNER JOIN returns only rows with matches in both tables. LEFT JOIN returns all rows from the left table, NULLs for no match on right." },
  { id:126, category:"Databases", question:"What is a foreign key?", options:["An encrypted primary key","A column that references the primary key of another table to enforce referential integrity","A composite key","An index key"], answer:1, explanation:"A foreign key creates a relationship between tables, ensuring referenced rows exist in the parent table." },
  { id:127, category:"Databases", question:"What is a database transaction?", options:["A stored procedure","A sequence of operations treated as a single unit — either all succeed or all fail","A type of index","A backup operation"], answer:1, explanation:"Transactions group operations atomically. If any step fails, the entire transaction rolls back to maintain consistency." },
  { id:128, category:"Databases", question:"What is the difference between DELETE and TRUNCATE?", options:["They are identical","DELETE removes specific rows and can be rolled back; TRUNCATE removes all rows faster and can't be rolled back","TRUNCATE uses WHERE clauses","DELETE is faster"], answer:1, explanation:"DELETE is logged row-by-row and supports WHERE. TRUNCATE drops and recreates the table — faster but irreversible." },
  { id:129, category:"Databases", question:"What is a covering index?", options:["An index on every column","An index that contains all columns needed by a query, avoiding a table lookup","A type of foreign key","A full-text index"], answer:1, explanation:"A covering index satisfies a query entirely from the index without accessing the table, making reads very fast." },
  { id:130, category:"Databases", question:"What is eventual consistency in databases?", options:["All reads always return the latest write","Given no new updates, all replicas will eventually converge to the same value","Data is never consistent across nodes","Only the primary is consistent"], answer:1, explanation:"Eventual consistency allows temporary inconsistency between replicas but guarantees convergence over time." },
  { id:131, category:"Databases", question:"What is a composite key?", options:["A key with encryption","A primary key made of two or more columns combined","A foreign key reference","An auto-increment key"], answer:1, explanation:"A composite key uses multiple columns together as a unique identifier when no single column is unique enough." },
  { id:132, category:"Databases", question:"What is the purpose of the GROUP BY clause?", options:["Sorts results","Groups rows sharing a value so aggregate functions apply to each group","Filters rows after aggregation","Joins tables"], answer:1, explanation:"GROUP BY groups rows with the same value so you can apply aggregates like COUNT, SUM, AVG per group." },
  { id:133, category:"Databases", question:"What is database denormalization?", options:["Removing all indexes","Intentionally adding redundancy to improve read performance at the cost of write complexity","Encrypting data","Dropping foreign keys"], answer:1, explanation:"Denormalization trades storage and write complexity for faster reads by duplicating data or precomputing joins." },
  { id:134, category:"Databases", question:"What is optimistic vs pessimistic locking in databases?", options:["They are the same","Optimistic assumes no conflict and checks at commit; pessimistic locks rows immediately on read","Pessimistic is always faster","Optimistic uses more memory"], answer:1, explanation:"Optimistic locking uses version numbers to detect conflicts at write time. Pessimistic locking acquires locks upfront." },
  { id:135, category:"Databases", question:"What is a stored procedure?", options:["A backup file","Precompiled SQL code stored in the DB that can be called by name","A type of index","A database trigger"], answer:1, explanation:"Stored procedures are reusable SQL code saved in the database — faster than sending raw SQL since they're precompiled." },
  { id:136, category:"Databases", question:"What is a database view?", options:["A physical copy of a table","A virtual table based on the result of a stored query","A type of index","A backup snapshot"], answer:1, explanation:"A view is a saved SELECT query that looks like a table — useful for simplifying complex queries and controlling access." },
  { id:137, category:"Databases", question:"What is the difference between HAVING and WHERE?", options:["No difference","WHERE filters rows before grouping; HAVING filters groups after GROUP BY","HAVING is faster","WHERE works on aggregates"], answer:1, explanation:"WHERE filters individual rows before aggregation. HAVING filters groups after GROUP BY — used with aggregates like COUNT > 5." },
  { id:138, category:"Databases", question:"What is a B-tree index?", options:["A binary search tree","A balanced tree structure used by most databases for indexes, supporting range queries","A hash index","A full-text search structure"], answer:1, explanation:"B-trees keep data sorted and balanced, enabling O(log n) lookups and efficient range queries — the default index in most databases." },
  { id:139, category:"Databases", question:"What is connection pooling?", options:["Storing query results","Maintaining a pool of reusable DB connections to avoid expensive connection creation per request","A replication strategy","A type of caching"], answer:1, explanation:"Connection pooling reuses existing DB connections, dramatically reducing latency and overhead for high-traffic applications." },
  { id:140, category:"Databases", question:"What is the difference between a clustered and non-clustered index?", options:["No difference","Clustered index determines physical row order (one per table); non-clustered is a separate structure","Non-clustered is faster","Clustered indexes can't be on primary keys"], answer:1, explanation:"A clustered index physically orders table rows — there can be only one. Non-clustered indexes are separate structures pointing to rows." },
];

